const today = new Date();
const mm = String(today.getMonth() + 1).padStart(2, '0');
const dd = String(today.getDate()).padStart(2, '0');
const todayKey = `${mm}-${dd}`;

const results = [];
for (const client of (items[0].json || [])) {
  if (!client.birthday || !client.email) continue;
  const bday = client.birthday.substring(5); // MM-DD
  if (bday !== todayKey) continue;
  const profile = client.profiles || {};
  results.push({
    json: {
      client_id: client.id,
      user_id: client.user_id,
      client_first_name: client.first_name,
      client_name: `${client.first_name} ${client.last_name}`,
      client_email: client.email,
      agent_name: profile.full_name || 'Alison Mendes',
      agent_business: profile.business_name || 'Visit & Smile'
    }
  });
}
return results;

